(1 row) 修改数据库对象隔离属性。 -- 创建用户jack。 gaussdb=# CREATE USER jack PASSWORD '********';
-- 在test_db1创建表test_tbl1。 gaussdb=# \c test_db1 gaussdb=# CREATE TABLE test_tbl1(c1 int,c2 int);
-- 切换至jack用户查看pg_tables。 gaussdb=# \c - jack       -- 切换用户为jack gaussdb=# SELECT tablename FROM pg_tables WHERE tablename = 'test_tbl1';
