-- 修改对象隔离属性。 gaussdb=# \c - omm        -- 切换用户为omm gaussdb=# \c test_db1     -- 切换数据库为test_db1 gaussdb=# ALTER DATABASE test_db1 ENABLE PRIVATE OBJECT;
-- 切换至jack用户查看pg_tables。 gaussdb=# \c - jack       -- 切换用户为jack
--由于隔离属性的原因，该查询只能查出0条数据。 gaussdb=# SELECT tablename FROM pg_tables WHERE tablename = 'test_tbl1';
