--删除 gaussdb=# \c - omm gaussdb=# \c test_db1 gaussdb=# DROP TABLE public.test_tbl1; gaussdb=# \c postgres gaussdb=# DROP DATABASE test_db1; gaussdb=# DROP TABLESPACE tbs_data1; gaussdb=# DROP USER jack; gaussdb=# DROP USER scott; 相关链接 CREATE DATABASE ， DROP DATABASE 。

ALTER TABLE SUBPARTITION ALTER TABLE SUBPARTITION 功能描述 修改二级分区表分区，包括增删分区、清空分区、切割/合并分区、移动分区表空间、交换分区、重命名分区，以及修改分区属性等。 注意事项 添加分区的表空间不能是PG_GLOBAL。 添加分区的名称不能与该分区表已有一级分区和二级分区的名称相同。 添加分区的分区键值要和分区表的分区键的类型一致。 若添加RANGE分区，添加分区键值要大于分区表中最后一个范围分区的上边界。若需要在有MAXVALUE分区的表上新增分区，建议使用SPLIT语法。 若添加LIST分区，添加分区键值不能与现有分区键值重复。若需要在有DEFAULT分区的表上新增分区，建议使用SPLIT语法。 不支持添加HASH分区。只有一种情况例外，二级分区表的二级分区方式为HASH且一级分区方式不是HASH，此时支持新增一级分区并创建对应的二级分区。 如果目标分区表中已有分区数达到了最大值1048575，则不能继续添加分区。 当分区表只有一个一级分区或二级分区时，不能删除该分区。 不支持删除HASH分区。 选择分区使用PARTITION FOR()或SUBPARTITION FOR()，括号里指定值个数应该与定义分区时使用的列个数相同，并且一一对应。 切割分区只能对二级分区（叶子节点）进行切割，被切割分区只能是Range、List分区策略，不支持切割hash分区策略。 合并分区只能对二级分区（叶子节点）进行合并，且源分区必须属于同一个一级分区。 只有分区表的所有者或者被授予了分区表ALTER权限的用户有权限执行ALTER TABLE PARTITION命令，系统管理员默认拥有此权限。 删除、切割、清空、交换分区的操作会使Global索引失效，可以申明UPDATE GLOBAL INDEX子句同步更新索引。 如果删除、切割、清空、交换分区操作不申明UPDATE GLOBAL INDEX子句，并发的DML业务有可能因为索引不可用而报错。 若设置参数enable_gpi_auto_update为on，即使不申明UPDATE GLOBAL INDEX子句，也会自动更新Global索引。 在为数据对象增加或者变更ILM策略的时候，如果追加了行级表达式，需要注意行表达式目前只支持白名单中列出的函数。具体白名单函数列表参考 行表达式函数白名单 。 语法格式 修改二级分区表分区包括修改表分区主语法、修改表分区名称的语法和重置分区ID的语法。 修改表分区主语法。 ALTER TABLE [ IF EXISTS ] { table_name  [*] | ONLY table_name | ONLY ( table_name  )}
    action [, ... ]; 其中action统指如下分区维护子语法。当存在多个分区维护子句时，保证了分区的连续性，无论这些子句的排序如何， GaussDB 总会先执行DROP PARTITION再执行ADD PARTITION操作，最后顺序执行其它分区维护操作。 move_clause  |
    exchange_clause  |
    row_clause  |
    merge_clause  |
    modify_clause  |
    add_clause    |
    drop_clause   |    
    split_clause  |
    truncate_clause move_clause子语法用于移动分区到新的表空间。 MOVE SUBPARTITION { subpartion_name | FOR ( subpartition_value [, ...] ) } TABLESPACE tablespacename exchange_clause子语法用于把普通表的数据迁移到指定的分区。 EXCHANGE SUBPARTITION { ( subpartition_name ) | FOR ( subpartition_value [, ...] ) } 
    WITH TABLE {[ ONLY ] ordinary_table_name | ordinary_table_name * | ONLY ( ordinary_table_name )} 
    [ { WITH | WITHOUT } VALIDATION ] [ VERBOSE ] [ UPDATE GLOBAL INDEX ] 进行交换的普通表和分区必须满足如下条件： 普通表和分区的列数目相同，对应列的信息严格一致，包括：列名、列的数据类型、列约束、列的Collation信息、列的存储参数、列的压缩信息等。 普通表和分区的表压缩信息严格一致。 普通表索引和分区Local索引个数相同，且对应索引的信息严格一致。 普通表和分区的表约束个数相同，且对应表约束的信息严格一致。 普通表不可以是临时表，分区表只能是二级分区表。 普通表和分区表上不可以有动态数据脱敏，行访问控制约束。 完成交换后，普通表和分区的数据被置换，同时普通表和分区的表空间信息被置换。此时，普通表和分区的统计信息变得不可靠，需要对普通表和分区重新执行analyze。 由于非分区键不能建立本地唯一索引，只能建立全局唯一索引，所以如果普通表含有唯一索引时，可能会导致不能交换数据。 如果需要进行数交换数据操作可以通过创建中间表的方式，先将分区数据插入到中间表，truncate分区，普通表数据插入分区表，drop普通表，重命名中间表的方式完成数据交换操作。 如果在普通表/分区表上进行了drop column操作，被删除的列依然物理存在，所以需要保证普通表和分区的被删除列也严格对齐才能交换成功。 row_clause子语法用于设置分区表的行迁移开关。 { ENABLE | DISABLE } ROW MOVEMENT merge_clause子语法用于把多个分区合并成一个分区。一个命令中合并的源分区上限为300。 MERGE SUBPARTITIONS { subpartition_name } [, ...] INTO SUBPARTITION partition_name 
    [ ILM ADD POLICY ROW STORE { COMPRESS ADVANCED } { ROW } AFTER n { day | month | year } OF { NO MODIFICATION } [ ON ( EXPR )]] [ TABLESPACE tablespacename ] [ UPDATE GLOBAL INDEX ] 对于范围分区，MERGE分区要求源分区的范围连续递增，且MERGE后的分区名可以与最后一个源分区名相同；对于列表分区，则源分区无顺序要求，且MERGE后的分区名可以与任一源分区名相同。如果MERGE后的分区名与源分区名相同，视为同一个分区。 未打开guc参数enable_ilm的情况下，如果使用merge_clause子语法把多个带有ilm policy的分区合并成一个分区，新分区不继承ilm policy。 USTORE存储引擎表不支持在事务块/存储过程中执行ALTER TABLE MERGE SUBPARTITIONS的操作。 modify_clause子语法用于设置分区索引是否可用。语法可以作用在一级分区上。 MODIFY PARTITION partition_name { UNUSABLE LOCAL INDEXES | REBUILD UNUSABLE LOCAL INDEXES } 也可以作用在二级分区上。 MODIFY SUBPARTITION partition_name { UNUSABLE LOCAL INDEXES | REBUILD UNUSABLE LOCAL INDEXES } add_clause子语法用于为指定的分区表添加一个或多个分区。语法可以作用在一级分区上。 ADD {partition_less_than_item | partition_list_item } [ ( subpartition_definition_list ) ] 也可以作用在二级分区上。 MODIFY PARTITION partition_name ADD subpartition_definition 其中，分区项partition_less_than_item为RANGE分区定义语法，具体语法如下。 PARTITION partition_name VALUES LESS THAN ( partition_value | MAXVALUE )[ ILM ADD POLICY ROW STORE { COMPRESS ADVANCED } { ROW } AFTER n { day | month | year } OF { NO MODIFICATION } [ ON ( EXPR )] ] [ TABLESPACE tablespacename ] 分区项partition_list_item为LIST分区定义语法，具体语法如下。 PARTITION partition_name VALUES ( partition_value [, ...] | DEFAULT ) [ ILM ADD POLICY ROW STORE { COMPRESS ADVANCED } { ROW } AFTER n { day | month | year } OF { NO MODIFICATION } [ ON ( EXPR )] ] [ TABLESPACE tablespacename ] subpartition_definition_list为1到多个二级分区subpartition_definition对象，subpartition_definition具体语法如下。 SUBPARTITION subpartition_name [ VALUES LESS THAN ( partition_value | MAXVALUE ) | VALUES ( partition_value [, ...] | DEFAULT )] [ ILM ADD POLICY ROW STORE { COMPRESS ADVANCED } { ROW } AFTER n { day | month | year } OF { NO MODIFICATION } [ ON ( EXPR )] ]  [ TABLESPACE tablespace ] 若一级分区为HASH分区，不支持以ADD形式新增一级分区；若二级分区为HASH分区，不支持以MODIFY形式新增二级分区。 drop_clause子语法用于删除分区表中的指定分区。语法可以作用在一级分区上。 DROP PARTITION  { partition_name | FOR (  partition_value )  } [ UPDATE GLOBAL INDEX ] 也可以作用在二级分区上。 DROP SUBPARTITION  { subpartition_name | FOR (  partition_value, subpartition_value )  } [ UPDATE GLOBAL INDEX ] 若一级分区为HASH分区，不支持删除一级分区；若二级分区为HASH分区，不支持删除二级分区。 不支持删除唯一子分区。 split_clause子语法用于把一个分区切割成多个分区。 SPLIT SUBPARTITION { subpartition_name| FOR ( subpartition_value [, ...] ) } { split_point_clause | no_split_point_clause } [ UPDATE GLOBAL INDEX ] SPLIT后的分区名可以与源分区名相同，但视为不同的分区。 未打开guc参数enable_ilm的情况下，如果使用split_clause子语法把一个带有ilm policy的分区分割成多个分区，新分区不继承ilm policy。 范围分区指定切割点split_point_clause的语法为： AT ( subpartition_value ) INTO ( SUBPARTITION subpartition_name [ TABLESPACE tablespacename ] , SUBPARTITION subpartition_name [ TABLESPACE tablespacename ] ) 切割点的大小要位于正在被切割的分区的分区键范围内，指定切割点的方式只能把一个分区切割成两个新分区。 范围分区不指定切割点no_split_point_clause 的语法如下，其中最后一个分区不能写分区范围定义，即VALUES LESS THAN (subpartition_value)部分，默认继承源分区范围定义的上界值。 INTO ( SUBPARTITION subpartition_name VALUES LESS THAN (subpartition_value) [ TABLESPACE tablespacename ][, ...] ) 第一个新分区的分区范围定义要大于正在被切割的分区的前一个分区（如果存在的话）的分区范围定义。 最后一个新分区不能写分区范围定义，默认继承源分区范围定义的上界值。 新分区必须满足分区范围定义递增的约束。 列表范围分区指定切割点split_point_clause的语法如下： VALUES ( subpartition_value ) INTO ( SUBPARTITION subpartition_name [ TABLESPACE tablespacename ] , SUBPARTITION subpartition_name [ TABLESPACE tablespacename ] ) 切割点必须是源分区的一个非空真子集，指定切割点的方式只能把一个分区切割成两个新分区。 列表分区表不指定切割点no_split_point_clause的语法如下，其中最后一个分区不能写分区范围定义，即VALUES (subpartition_value_list)部分，其范围等于源分区去掉其他子分区后的剩余集合。 INTO ( SUBPARTITION subpartition_name VALUES (subpartition_value_list) [ TABLESPACE tablespacename ][, ...] ) 最后一个新分区不能写分区范围定义，其范围等于源分区去掉其他子分区后的剩余集合。 不指定切割点的方式，每一个新分区都必须是源分区的一个非空真子集，且互不交叉。 truncate_clause子语法用于清空分区表中的指定分区。语法可以作用在一级分区上。 TRUNCATE PARTITION  { partition_name | FOR (  partition_value [, ...] )  } [ UPDATE GLOBAL INDEX ] 也可以作用在二级分区上。 TRUNCATE SUBPARTITION  { subpartition_name | FOR (  subpartition_value [, ...] )  } [ UPDATE GLOBAL INDEX ] 修改表分区名称的语法。可以修改分区表的一级分区。 ALTER TABLE [ IF EXISTS ] { table_name [*] | ONLY table_name | ONLY ( table_name  )}
    RENAME PARTITION { partion_name | FOR ( partition_value [, ...] ) } TO partition_new_name; 也可以修改分区表的二级分区。 ALTER TABLE [ IF EXISTS ] { table_name [*] | ONLY table_name | ONLY ( table_name  )}
    RENAME SUBPARTITION { subpartion_name | FOR ( subpartition_value [, ...] ) } TO subpartition_new_name; 重置分区ID的语法。 ALTER TABLE [ IF EXISTS ] { table_name [*] | ONLY table_name | ONLY ( table_name  )} RESET PARTITION; 参数说明 table_name 分区表名。 取值范围：已存在的分区表名。 subpartition_name 二级分区名。 取值范围：已存在的二级分区名。 tablespacename 指定分区要移动到哪个表空间。 取值范围：已存在的表空间名。 partition_value 一级分区键值。 通过PARTITION FOR ( partition_value [, ...] )子句指定的这一组值，可以唯一确定一个一级分区。 取值范围：需要进行操作的一级分区的分区键的取值范围。 subpartition_value 一级分区键值和二级分区键值。 通过SUBPARTITION FOR ( subpartition_value [, ...] )子句指定的这一组值，可以唯一确定一个二级分区。 取值范围：对于需要进行操作的二级分区，需要同时有其一级分区分区键和二级分区分区键的取值范围。 UNUSABLE LOCAL INDEXES 设置该分区上的所有索引不可用。 REBUILD UNUSABLE LOCAL INDEXES 重建该分区上的所有索引。 { ENABLE | DISABLE } ROW MOVEMET 行迁移开关。 如果进行UPDATE操作时，更新了元组在分区键上的值，造成了该元组所在分区发生变化，就会根据该开关给出报错信息，或者进行元组在分区间的转移。 取值范围： ENABLE：打开行迁移开关。 DISABLE：关闭行迁移开关。 默认是打开状态。 ordinary_table_name 进行迁移的普通表的名称。 取值范围：已存在的普通表名。 { WITH | WITHOUT } VALIDATION 在进行数据迁移时，是否检查普通表中的数据满足指定分区的分区键范围。 取值范围： WITH：对于普通表中的数据要检查是否满足分区的分区键范围，如果有数据不满足，则报错。 WITHOUT：对于普通表中的数据不检查是否满足分区的分区键范围。 默认是WITH状态。 由于检查比较耗时，特别是当数据量很大的情况下更甚。所以在保证当前普通表中的数据满足分区的分区键范围时，可以加上WITHOUT来指明不进行检查。 VERBOSE 在VALIDATION是WITH状态时，如果检查出普通表有不满足要交换分区的分区键范围的数据，那么把这些数据插入到正确的分区，如果路由不到任何分区，再报错。 只有在VALIDATION是WITH状态时，才可以指定VERBOSE。 partition_new_name 分区的新名称。 取值范围：字符串，要符合 标识符命名规范 。 subpartition_new_name 二级分区的新名称。 取值范围：字符串，要符合 标识符命名规范 。 UPDATE GLOBAL INDEX 如果使用该参数，则会更新分区表上的所有全局索引，以确保使用全局索引可以查询出正确的数据；如果不使用该参数，则分区表上的所有全局索引将会失效。 示例 请参考 CREATE TABLE SUBPARTITION 的示例。 相关链接 CREATE TABLE SUBPARTITION

ALTER AGGREGATE ALTER AGGREGATE 功能描述 修改一个聚合函数的定义。包括名称、所有者和模式。 注意事项 要使用ALTER AGGREGATE，你必须是该聚合函数的所有者。要改变一个聚合函数的模式，你必须在新模式上有CREATE权限。 要改变所有者，你必须是新所有角色的一个直接或间接成员，并且该角色必须在聚合函数的所属模式上有CREATE权限。（这些限制强制了修改该所有者时不会做任何通过删除和重建聚合函数不能做的事情。不过，具有SYSADMIN权限的用户可以用任何方法任意更改聚合函数的所属关系）。 语法格式 ALTER AGGREGATE name ( argtype [ , ... ] ) RENAME TO new_name;
ALTER AGGREGATE name ( argtype [ , ... ] ) OWNER TO new_owner;
ALTER AGGREGATE name ( argtype [ , ... ] ) SET SCHEMA new_schema; 参数说明 name 现有的聚合函数的名称(可以有模式修饰)。 argtype 聚合函数操作的输入数据类型。要引用一个零参数聚合函数，可以写入*代替输入数据类型列表。 new_name 聚合函数的新名字。 new_owner 聚合函数的新所有者。 new_schema 聚合函数的新模式。 示例 -- 创建自定义函数。 gaussdb=# CREATE OR REPLACE FUNCTION int_add(int,int)
	returns int as $BODY$
declare
begin
	return $1 + $2;
end;
$BODY$ language plpgsql;

-- 创建聚合函数。 gaussdb=# CREATE AGGREGATE myavg (int)
(
    sfunc = int_add,
    stype = int,
    initcond = '0'
);

--把一个接受integer 类型参数的聚合函数myavg重命名为 my_average 。 gaussdb=# ALTER AGGREGATE myavg(integer) RENAME TO my_average;

--创建用户joe。 gaussdb=# CREATE USER joe PASSWORD ' ******** ';

--把一个接受integer 类型参数的聚合函数myavg的所有者改为joe 。 gaussdb=# ALTER AGGREGATE my_average(integer) OWNER TO joe;

--创建SCHEMA。 gaussdb=# CREATE SCHEMA myschema;

--把一个接受integer 类型参数的聚合函数myavg移动到模式myschema里。 gaussdb=# ALTER AGGREGATE my_average(integer) SET SCHEMA myschema;

--删除SCHEMA,用户及相关函数。 gaussdb=# DROP SCHEMA myschema CASCADE; gaussdb=# DROP USER joe; gaussdb=# DROP FUNCTION int_add(int,int); 相关链接 CREATE AGGREGATE ， DROP AGGREGATE 兼容性 SQL标准里没有ALTER AGGREGATE语句。

ALTER PACKAGE ALTER PACKAGE 功能描述 修改PACKAGE的属性或重编译包。 注意事项 目前仅支持ALTER PACKAGE OWNER功能，系统管理员默认拥有该权限，有以下权限约束： 当前用户必须是该package的所有者或者系统管理员，且该用户是新所有者角色的成员。 重编译包需要设置plpgsql_dependency参数。 当打开三权分立时，即使是系统管理员，也必须拥有用户组权限才能修改package的owner。 只有初始化用户才能修改package的owner为初始化用户。 三权分立模式下，DEFINER类型package不允许修改所有者。非三权分立模式下，仅系统管理员以上权限可以修改package所有者。 不允许系统管理员将DEFINER类型的package的所有者改为初始用户或运维管理员。 语法格式 修改package的所有者。 ALTER PACKAGE package_name OWNER TO new_owner; 重编译包 ALTER PACKAGE package_name COMPILE [PACKAGE | BODY | SPECIFICATION]; 参数说明 package_name 要修改的package名称。 取值范围：已存在的package名，仅支持修改单个package。 new_owner package的新所有者。要修改函数的所有者，新所有者必须拥有该package所属模式的CREATE权限。 取值范围：已存在的用户角色。 示例 请参见 CREATE PACKAGE 中示例。 重编译示例： -- 开启依赖功能 gaussdb=# SET behavior_compat_options ='plpgsql_dependency';

-- 创建包 gaussdb=# CREATE OR REPLACE PACKAGE TEST_PKG
AS
    pkg_var int := 1;
    PROCEDURE test_pkg_proc(var int);
end TEST_PKG;
/ gaussdb=# CREATE OR REPLACE PACKAGE BODY TEST_PKG 
AS
    PROCEDURE test_pkg_proc(var int)
IS
BEGIN
    pkg_var := 1;
END;
END TEST_PKG;
/

-- 重编译包 gaussdb=# ALTER PACKAGE test_pkg COMPILE;

-- 删除包 gaussdb=# DROP PACKAGE TEST_PKG;

-- 关闭依赖功能 gaussdb=# SET behavior_compat_options = ''; 相关链接 CREATE PACKAGE ， DROP PACKAGE

ALTER DATABASE LINK ALTER DATABASE LINK 功能描述 修改DATABASE LINK对象。DATABASE LINK详细说明请见 DATABASE LINK 。 注意事项 目前仅支持修改DATABASE LINK对象的用户名和密码。 语法格式 ALTER [ PUBLIC ] DATABASE LINK dblink CONNECT TO user IDENTIFIED BY password ; 参数说明 dblink 连接名称。 user 远端被连接数据库用户名。 password 远端被连接数据库用户密码。 PUBLIC 连接类型，不加PUBLIC默认PRIVATE。 示例 --创建拥有系统管理员权限的用户 gaussdb=# CREATE USER user01 WITH SYSADMIN PASSWORD '********'; gaussdb=# SET ROLE user01 PASSWORD '********';

--创建公共dblink gaussdb=# CREATE PUBLIC DATABASE LINK public_dblink CONNECT TO 'user1' IDENTIFIED BY '********' USING (host '192.168.11.11',port '54399',dbname 'db01');

--创建普通用户 gaussdb=# CREATE USER user2 PASSWORD '********';

-- 修改dblink对象信息 gaussdb=# ALTER PUBLIC DATABASE LINK public_dblink CONNECT TO 'user2' IDENTIFIED BY '********';

--删除公共dblink gaussdb=# DROP PUBLIC DATABASE LINK public_dblink;

--删除创建出的用户 gaussdb=# RESET ROLE; gaussdb=# DROP USER user01 CASCADE; gaussdb=# DROP USER user02; 相关链接 CREATE DATABASE LINK ， DROP DATABASE LINK

ALTER TABLE PARTITION ALTER TABLE PARTITION 功能描述 修改表分区，包括增加/删除分区、切割/合并分区、清空分区、移动分区表空间、交换分区、重命名分区，以及修改分区属性等。 注意事项 只有分区表的所有者或者被授予了分区表ALTER权限的用户有权限执行ALTER TABLE PARTITION命令，系统管理员默认拥有此权限。 添加分区的表空间不能是PG_GLOBAL。 添加分区的名称不能与该分区表已有分区的名称相同。 添加分区的分区键值要和分区表的分区键的类型一致。 若添加RANGE分区，添加分区键值要大于分区表中最后一个范围分区的上边界。 若添加LIST分区，添加分区键值不能与现有分区键值重复。 不支持添加HASH分区。 如果目标分区表中已有分区数达到了最大值1048575，则不能继续添加分区。 当分区表只有一个分区时，不能删除该分区。 选择分区使用PARTITION FOR()，括号里指定值个数应该与定义分区时使用的列个数相同，并且一一对应。 Value分区表不支持相应的Alter Partition操作。 间隔分区表不支持添加分区。 哈希分区表不支持切割分区，不支持合成分区，不支持添加和删除分区。 删除、切割、合并、清空、交换分区的操作会使Global索引失效，可以申明UPDATE GLOBAL INDEX子句同步更新索引。 如果删除、切割、合并、清空、交换分区操作不申明UPDATE GLOBAL INDEX子句，并发的DML业务有可能因为索引不可用而报错。 若设置参数enable_gpi_auto_update为on，即使不申明UPDATE GLOBAL INDEX子句，也会自动更新Global索引。 在为数据对象增加或者变更ILM策略的时候，如果追加了行级表达式，需要注意行表达式目前只支持白名单中列出的函数。具体白名单函数列表参考 行表达式函数白名单 。 语法格式 修改分区表分区包括修改表分区主语法、修改表分区名称的语法和重置分区ID的语法。 修改表分区主语法。 ALTER TABLE [ IF EXISTS ] { table_name  [*] | ONLY table_name | ONLY ( table_name  )}
    action [, ... ]; 其中action统指如下分区维护子语法。当存在多个分区维护子句时，保证了分区的连续性，无论这些子句的排序如何， GaussDB 总会先执行DROP PARTITION再执行ADD PARTITION操作，最后顺序执行其它分区维护操作。 move_clause  |
    exchange_clause  |
    row_clause  |
    merge_clause  |
    modify_clause  |
    split_clause  |
    add_clause  |
    drop_clause  |
    truncate_clause  |
    ilm_clause move_clause子语法用于移动分区到新的表空间。 MOVE PARTITION { partion_name | FOR ( partition_value [, ...] ) } TABLESPACE tablespacename exchange_clause子语法用于把普通表的数据迁移到指定的分区。 EXCHANGE PARTITION { ( partition_name ) | partition_name | FOR ( partition_value [, ... ] ) } 
    WITH TABLE {[ ONLY ] ordinary_table_name | ordinary_table_name * | ONLY ( ordinary_table_name )} 
    [ { WITH | WITHOUT } VALIDATION ] [ VERBOSE ] [ UPDATE GLOBAL INDEX ] [ UPDATE DISTRIBUTED GLOBAL INDEX | NO UPDATE DISTRIBUTED GLOBAL INDEX ] 进行交换的普通表和分区必须满足如下条件： 普通表和分区的列数目相同，对应列的信息严格一致，包括：列名、列的数据类型、列约束、列的Collation信息、列的存储参数、列的压缩信息等。 普通表和分区的表压缩信息严格一致。 普通表索引和分区Local索引个数相同，且对应索引的信息严格一致。 普通表和分区的表约束个数相同，且对应表约束的信息严格一致。 普通表不可以是临时表，分区表只能是范围分区表，列表分区表，哈希分区表或间隔分区表。 普通表和分区表上不可以有动态数据脱敏，行访问控制约束。 完成交换后，普通表和分区的数据被置换，同时普通表和分区的表空间信息被置换。此时，普通表和分区的统计信息变得不可靠，需要对普通表和分区重新执行analyze。 由于非分区键不能建立本地唯一索引，只能建立全局唯一索引，所以如果普通表含有唯一索引时，可能会导致不能交换数据。 如果需要进行数交换数据操作可以通过创建中间表的方式，先将分区数据插入到中间表，truncate分区，普通表数据插入分区表，drop普通表，重命名中间表的方式完成数据交换操作。 如果在普通表/分区表上进行了DROP COLUMN操作，被删除的列依然物理存在，所以需要保证普通表和分区的被删除列也严格对齐才能交换成功。 EXCHANGE PARTITION { ( partition_name ) | partition_name | FOR ( partition_value [, ... ] ) } 操作在B模式数据库（即sql_compatibility = 'B'）下 可用 ，其他模式下仅 EXCHANGE PARTITION { ( partition_name ) | FOR ( partition_value [, ... ] ) }可用 。 在B模式数据库（即sql_compatibility = 'B'）下，当partition_name为一级分区名时，进行交换的是一级分区和普通表；当partition_name为二级分区时， 进行交换的是二级分区和普通表。 不支持在二级分区表中交换一级分区和普通表。 进行分区交换后，自增列不会被重置。 row_clause子语法用于设置分区表的行迁移开关。 { ENABLE | DISABLE } ROW MOVEMENT merge_clause子语法用于把多个分区合并成一个分区。一个命令中合并的源分区上限为300。 MERGE PARTITIONS { partition_name } [, ...] INTO PARTITION partition_name 
    [ ILM ADD POLICY ROW STORE { COMPRESS ADVANCED } { ROW } AFTER n { day | month | year } OF { NO MODIFICATION } [ ON ( EXPR )] ] [ TABLESPACE tablespacename ] [ UPDATE GLOBAL INDEX ] [ UPDATE DISTRIBUTED GLOBAL INDEX | NO UPDATE DISTRIBUTED GLOBAL INDEX ] 对于范围分区/间隔分区，MERGE分区要求源分区的范围连续递增，且MERGE后的分区名可以与最后一个源分区名相同；对于列表分区，则源分区无顺序要求，且MERGE后的分区名可以与任一源分区名相同。如果MERGE后的分区名与源分区名相同，视为同一个分区。 未打开guc参数enable_ilm的情况下，如果使用merge_clause子语法把多个带有ilm policy的分区合并成一个分区，新分区不继承ilm policy。 USTORE存储引擎表不支持在事务块/存储过程中执行ALTER TABLE MERGE PARTITIONS的操作。 modify_clause子语法用于设置分区索引是否可用。 MODIFY PARTITION partition_name { UNUSABLE LOCAL INDEXES | REBUILD UNUSABLE LOCAL INDEXES } [ ILM ADD POLICY ROW STORE { COMPRESS ADVANCED } { ROW } AFTER n { day | month | year } OF { NO MODIFICATION } [ ON ( EXPR )] ] split_clause子语法用于把一个分区切割成多个分区。 SPLIT PARTITION { partition_name | FOR ( partition_value [, ...] ) } { split_point_clause | no_split_point_clause } [ UPDATE GLOBAL INDEX ] [ UPDATE DISTRIBUTED GLOBAL INDEX | NO UPDATE DISTRIBUTED GLOBAL INDEX ] SPLIT后的分区名可以与源分区名相同，但视为不同的分区。 未打开guc参数enable_ilm的情况下，如果使用split_clause子语法把一个带有ilm policy的分区分割成多个分区，新分区不继承ilm policy。 范围分区表和间隔分区表指定切割点split_point_clause的语法为： AT ( partition_value ) INTO ( PARTITION partition_name [ TABLESPACE tablespacename ] , PARTITION partition_name [ TABLESPACE tablespacename ] ) 切割点的大小要位于正在被切割的分区的分区键范围内，指定切割点的方式只能把一个分区切割成两个新分区。 范围分区表和间隔分区表不指定切割点no_split_point_clause的语法为： INTO { ( partition_less_than_item [, ...] ) | ( partition_start_end_item [, ...] ) } 不指定切割点的方式，partition_less_than_item指定的第一个新分区的分区键要大于正在被切割的分区的前一个分区（如果存在的话）的分区键，partition_less_than_item指定的最后一个分区的分区键要等于正在被切割的分区的分区键大小。 不指定切割点的方式，partition_start_end_item指定的第一个新分区的起始点（如果存在的话）必须等于正在被切割的分区的前一个分区（如果存在的话）的分区键，partition_start_end_item指定的最后一个分区的终止点（如果存在的话）必须等于正在被切割的分区的分区键。 partition_less_than_item支持的分区键个数最多为16，而partition_start_end_item仅支持1个分区键，其支持的数据类型请参见 •PARTITION BY RANGE [COLUMNS] (partition_key) 。 在同一语句中partition_less_than_item和partition_start_end_item两者不可同时使用；不同split语句之间没有限制。 分区项partition_less_than_item的语法如下，其中最后一个分区可以不写分区范围定义，即VALUES LESS THAN (partition_value)部分，默认继承源分区范围定义的上界值。 PARTITION partition_name VALUES LESS THAN ( { partition_value | MAXVALUE }  [, ...] ) 
    [ ILM ADD POLICY ROW STORE { COMPRESS ADVANCED } { ROW } AFTER n { day | month | year } OF { NO MODIFICATION } [ ON ( EXPR )] ] [ TABLESPACE tablespacename ] 分区项partition_start_end_item的语法如下，其约束请参见 START END语法描述 。 PARTITION partition_name {
        {START(partition_value) END (partition_value) EVERY (interval_value)} |
        {START(partition_value) END ({partition_value | MAXVALUE})} |
        {START(partition_value)} |
        {END({partition_value | MAXVALUE})}
} [ ILM ADD POLICY ROW STORE { COMPRESS ADVANCED } { ROW } AFTER n { day | month | year } OF { NO MODIFICATION } [ ON ( EXPR )] ] [TABLESPACE tablespace_name] 列表分区表指定切割点split_point_clause的语法如下： VALUES ( partition_value_list ) INTO ( PARTITION partition_name [ ILM ADD POLICY ROW STORE { COMPRESS ADVANCED } { ROW } AFTER n { day | month | year } OF { NO MODIFICATION } [ ON ( EXPR )]] [ TABLESPACE tablespacename ] , PARTITION partition_name [ ILM ADD POLICY ROW STORE { COMPRESS ADVANCED } { ROW } AFTER n { day | month | year } OF { NO MODIFICATION } [ ON ( EXPR )]] [ TABLESPACE tablespacename ] ) 切割点必须是源分区的一个非空真子集，指定切割点的方式只能把一个分区切割成两个新分区。 列表分区表不指定切割点no_split_point_clause的语法如下，其中最后一个分区不能写分区范围定义，即VALUES (partition_value_list)部分，其范围等于源分区去掉其他子分区后的剩余集合。 INTO ( PARTITION partition_name VALUES (partition_value_list) [ TABLESPACE tablespacename ][, ...] ) 最后一个新分区不能写分区范围定义，其范围等于源分区去掉其他子分区后的剩余集合。 不指定切割点的方式，每一个新分区都必须是源分区的一个非空真子集，且互不交叉。 add_clause子语法用于为指定的分区表添加一个或多个分区。 ADD {partition_less_than_item | partition_start_end_item| partition_list_item } 分区项partition_list_item的语法如下。 PARTITION partition_name VALUES (list_values_clause) 
    [ ILM ADD POLICY ROW STORE { COMPRESS ADVANCED } { ROW } AFTER n { day | month | year } OF { NO MODIFICATION } [ ON ( EXPR )] ] [ TABLESPACE tablespacename ] partition_list_item支持最多16个分区键，其支持的数据类型请参见 •PARTITION BY LIST [COLUMNS] (partition_key) 。 间隔/哈希分区表不支持添加分区。 drop_clause子语法用于删除分区表中的指定分区。 DROP PARTITION  { partition_name | FOR (  partition_value [, ...] )  } [ UPDATE GLOBAL INDEX ] [ UPDATE DISTRIBUTED GLOBAL INDEX | NO UPDATE DISTRIBUTED GLOBAL INDEX ] 哈希分区表不支持删除分区。 当分区表只有一个分区时，不能删除该分区。 truncate_clause子语法用于清空分区表中的指定分区。 TRUNCATE PARTITION  { partition_name | FOR (  partition_value [, ...] )  } [ UPDATE GLOBAL INDEX ] [ UPDATE DISTRIBUTED GLOBAL INDEX | NO UPDATE DISTRIBUTED GLOBAL INDEX ] 修改表分区名称的语法。 ALTER TABLE [ IF EXISTS ] { table_name [*] | ONLY table_name | ONLY ( table_name  )}
    RENAME PARTITION { partion_name | FOR ( partition_value [, ...] ) } TO partition_new_name; 重置分区ID的语法。 ALTER TABLE [ IF EXISTS ] { table_name [*] | ONLY table_name | ONLY ( table_name  )} RESET PARTITION; 参数说明 table_name 分区表名。 取值范围：已存在的分区表名。 partition_name 分区名。 取值范围：已存在的分区名。 tablespacename 指定分区要移动到哪个表空间。 取值范围：已存在的表空间名。 partition_value 分区键值。 通过PARTITION FOR ( partition_value [, ...] )子句指定的这一组值，可以唯一确定一个分区。 取值范围：需要进行操作的分区的分区键的取值范围。 UNUSABLE LOCAL INDEXES 设置该分区上的所有索引不可用。 REBUILD UNUSABLE LOCAL INDEXES 重建该分区上的所有索引。 { ENABLE | DISABLE } ROW MOVEMET 行迁移开关。 如果进行UPDATE操作时，更新了元组在分区键上的值，造成了该元组所在分区发生变化，就会根据该开关给出报错信息，或者进行元组在分区间的转移。 取值范围： ENABLE：打开行迁移开关。 DISABLE：关闭行迁移开关。 默认是打开状态。 ordinary_table_name 进行迁移的普通表的名称。 取值范围：已存在的普通表名。 { WITH | WITHOUT } VALIDATION 在进行数据迁移时，是否检查普通表中的数据满足指定分区的分区键范围。 取值范围： WITH：对于普通表中的数据要检查是否满足分区的分区键范围，如果有数据不满足，则报错。 WITHOUT：对于普通表中的数据不检查是否满足分区的分区键范围。 默认是WITH状态。 由于检查比较耗时，特别是当数据量很大的情况下更甚。所以在保证当前普通表中的数据满足分区的分区键范围时，可以加上WITHOUT来指明不进行检查。 VERBOSE 在VALIDATION是WITH状态时，如果检查出普通表有不满足要交换分区的分区键范围的数据，那么把这些数据插入到正确的分区，如果路由不到任何分区，再报错。 只有在VALIDATION是WITH状态时，才可以指定VERBOSE。 partition_new_name 分区的新名称。 取值范围：字符串，要符合 标识符命名规范 。 UPDATE GLOBAL INDEX 如果使用该参数，则会更新分区表上的所有全局索引，以确保使用全局索引可以查询出正确的数据。如果不使用该参数，则分区表上的所有全局索引将会失效。 UPDATE DISTRIBUTED GLOBAL INDEX | NO UPDATE DISTRIBUTED GLOBAL INDEX 可选重建或者失效基表的全局二级索引。 删除、切割、合并、清空、交换分区的操作中的此选项集中式不支持。 示例 请参见CREATE TABLE PARTITION的 示例 。 相关链接 CREATE TABLE PARTITION ， DROP TABLE

ALTER MATERIALIZED VIEW ALTER MATERIALIZED VIEW 功能描述 更改一个现有物化视图的多个辅助属性。 可用于ALTER MATERIALIZED VIEW的语句形式和动作是ALTER TABLE的一个子集，并且在用于物化视图时具有相同的含义。详见 ALTER TABLE 。 注意事项 只有物化视图的所有者有权限执行ALTER MATERIALIZED VIEW命令，系统管理员默认拥有此权限。 不支持更改物化视图结构。 语法格式 修改物化视图的所属用户。 ALTER MATERIALIZED VIEW [ IF EXISTS ] mv_name
    OWNER TO new_owner; 修改物化视图的列。 ALTER MATERIALIZED VIEW [ IF EXISTS ] mv_name
    RENAME [ COLUMN ] column_name TO new_column_name; 重命名物化视图。 ALTER MATERIALIZED VIEW [ IF EXISTS ] mv_name
    RENAME TO new_name; 参数说明 mv_name 一个现有物化视图的名称，可以用模式修饰。 取值范围：字符串，符合 标识符命名规范 。 column_name 一个新的或者现有的列的名称。 取值范围：字符串，符合 标识符命名规范 。 new_column_name 一个现有列的新名称。 new_owner 该物化视图的新拥有者的用户名。 new_name 该物化视图的新名称。 示例 --创建表。 gaussdb=# CREATE TABLE my_table (c1 int, c2 int) WITH(STORAGE_TYPE=ASTORE);

--创建全量物化视图。 gaussdb=# CREATE MATERIALIZED VIEW foo AS SELECT * FROM my_table;

--把物化视图foo重命名为bar。 gaussdb=# ALTER MATERIALIZED VIEW foo RENAME TO bar;

--删除全量物化视图。 gaussdb=# DROP MATERIALIZED VIEW bar;

--删除表my_table。 gaussdb=# DROP TABLE my_table; 相关链接 CREATE INCREMENTAL MATERIALIZED VIEW ， CREATE MATERIALIZED VIEW ， DROP MATERIALIZED VIEW ， REFRESH INCREMENTAL MATERIALIZED VIEW ， REFRESH MATERIALIZED VIEW

ABORT ABORT 功能描述 回滚当前事务并且撤销所有当前事务中所做的更改。 作用等同于 ROLLBACK ，早期SQL有用ABORT，现在推荐使用ROLLBACK。 注意事项 在事务外部执行ABORT语句不会影响事务的执行，但会返回一个NOTICE信息。 语法格式 ABORT [ WORK | TRANSACTION ]; 参数说明 WORK | TRANSACTION 可选关键字，除了增加可读性没有其他任何作用。 示例 --创建表customer_demographics_t1。 gaussdb=# CREATE TABLE customer_demographics_t1
(
    CD_DEMO_SK                INTEGER               NOT NULL,
    CD_GENDER                 CHAR(1)                       ,
    CD_MARITAL_STATUS         CHAR(1)                       ,
    CD_EDUCATION_STATUS       CHAR(20)                      ,
    CD_PURCHASE_ESTIMATE      INTEGER                       ,
    CD_CREDIT_RATING          CHAR(10)                      ,
    CD_DEP_COUNT              INTEGER                       ,
    CD_DEP_EMPLOYED_COUNT     INTEGER                       ,
    CD_DEP_COLLEGE_COUNT      INTEGER
)
;

--插入记录。 gaussdb=# INSERT INTO customer_demographics_t1 VALUES(1920801,'M', 'U', 'DOCTOR DEGREE', 200, 'GOOD', 1, 0,0);

--开启事务。 gaussdb=# START TRANSACTION;

--更新字段值。 gaussdb=# UPDATE customer_demographics_t1 SET cd_education_status= 'Unknown';

--终止事务，上面所执行的更新会被撤销掉。 gaussdb=# ABORT; 

--查询数据。 gaussdb=# SELECT * FROM customer_demographics_t1 WHERE cd_demo_sk = 1920801;
cd_demo_sk | cd_gender | cd_marital_status | cd_education_status  | cd_purchase_estimate | cd_credit_rating | cd_dep_count | cd_dep_employed_count | cd_dep_college_count 
------------+-----------+-------------------+----------------------+----------------------+------------------+--------------+-----------------------+----------------------
    1920801 | M         | U                 | DOCTOR DEGREE        |                  200 | GOOD             |            1 |                     0 |                    0
(1 row)

--删除表。 gaussdb=# DROP TABLE customer_demographics_t1; 相关链接 SET TRANSACTION ， COMMIT | END ， ROLLBACK

ALTER ROLE ALTER ROLE 功能描述 修改角色属性。 注意事项 无。 语法格式 修改角色的权限。 ALTER ROLE role_name [ [ WITH ] option [ ... ] ]; 其中权限项子句option为： {CREATEDB | NOCREATEDB}
    | {CREATEROLE | NOCREATEROLE}
    | {INHERIT | NOINHERIT}
    | {AUDITADMIN | NOAUDITADMIN}
    | {SYSADMIN | NOSYSADMIN}
    | {MONADMIN | NOMONADMIN}
    | {OPRADMIN | NOOPRADMIN}
    | {POLADMIN | NOPOLADMIN}
    | {USEFT | NOUSEFT}
    | {LOGIN | NOLOGIN}
    | {REPLICATION | NOREPLICATION}
    | {VCADMIN | NOVCADMIN}
    | {PERSISTENCE | NOPERSISTENCE}
    | CONNECTION LIMIT connlimit
    | [ ENCRYPTED | UNENCRYPTED ] PASSWORD 'password' [EXPIRED]
    | [ ENCRYPTED | UNENCRYPTED ] IDENTIFIED BY 'password' [ REPLACE 'old_password' | EXPIRED ]
    | [ ENCRYPTED | UNENCRYPTED ] PASSWORD { 'password' | DISABLE | EXPIRED }
    | [ ENCRYPTED | UNENCRYPTED ] IDENTIFIED BY { 'password' [ REPLACE 'old_password' ] | DISABLE }
    | VALID BEGIN 'timestamp'
    | VALID UNTIL 'timestamp'
    | RESOURCE POOL 'respool'
    | PERM SPACE 'spacelimit'
    | PGUSER 修改角色的名称： ALTER ROLE role_name 
    RENAME TO new_name; 锁定或解锁： ALTER ROLE role_name 
    ACCOUNT { LOCK | UNLOCK }; 设置角色的配置参数： ALTER ROLE role_name [ IN DATABASE database_name ]
    SET configuration_parameter {{ TO | = } { value | DEFAULT } | FROM CURRENT}; 重置角色的配置参数： ALTER ROLE role_name
    [ IN DATABASE database_name ] RESET {configuration_parameter|ALL}; 参数说明 role_name 现有角色名。 取值范围：已存在的用户名。 IN DATABASE database_name 表示修改角色在指定数据库上的参数。 SET configuration_parameter {{ TO | = } { value | DEFAULT } | FROM CURRENT} 设置角色的参数。ALTER ROLE中修改的会话参数只针对指定的角色，且在下一次该角色启动的会话中有效。 取值范围： configuration_parameter和value的取值请参见 SET 。 DEFAULT：表示清除configuration_parameter参数的值，configuration_parameter参数的值将继承本角色新产生的SESSION的默认值。 FROM CURRENT：取当前会话中的值设置为configuration_parameter参数的值。 RESET {configuration_parameter|ALL} 清除configuration_parameter参数的值。与SET configuration_parameter TO DEFAULT的效果相同。 取值范围：ALL表示清除所有参数的值。 ACCOUNT LOCK | ACCOUNT UNLOCK ACCOUNT LOCK：锁定账户，禁止登录数据库。 ACCOUNT UNLOCK：解锁账户，允许登录数据库。 PGUSER 当前版本不允许修改角色的PGUSER属性 {PASSWORD|IDENTIFIED BY} 'password' 重置或修改用户密码。除了初始用户外其他管理员或普通用户修改自己的密码需要输入正确的旧密码。只有初始用户、系统管理员（sysadmin）或拥有创建用户（CREATEROLE）权限的用户才可以重置普通用户密码，无需输入旧密码。初始用户可以重置系统管理员的密码，系统管理员不允许重置其他系统管理员的密码。应当使用单引号将用户密码括起来。 EXPIRED 设置密码失效。只有初始用户、系统管理员（sysadmin）或拥有创建用户（CREATEROLE）权限的用户才可以设置用户密码失效，其中系统管理员也可以设置自己或其他系统管理员密码失效。不允许设置初始用户密码失效。 密码失效的用户可以登录数据库但不能执行查询操作，只有修改密码或由管理员重置密码后才可以恢复正常查询操作。 其他参数请参见CREATE ROLE的 参数说明 。 示例 请参见CREATE ROLE的 示例 。 相关链接 CREATE ROLE ， DROP ROLE ， SET ROLE

ALTER SESSION ALTER SESSION 功能描述 ALTER SESSION命令用于定义或修改那些对当前会话有影响的条件或参数。修改后的会话参数会一直保持，直到断开当前会话。 注意事项 如果执行SET TRANSACTION之前没有执行START TRANSACTION，则事务立即结束，命令无法显示效果。 可以用START TRANSACTION里面声明所需要的transaction_mode(s)的方法来避免使用SET TRANSACTION。具体请参见： START TRANSACTION 。 语法格式 设置会话的事务参数。 ALTER SESSION SET [ SESSION CHARACTERISTICS AS ] TRANSACTION
    { ISOLATION LEVEL { READ COMMITTED } | { READ ONLY  | READ WRITE } } [, ...] ; 设置会话的其他运行时参数。 ALTER SESSION SET 
    {{config_parameter { { TO  | =  }  { value | DEFAULT } | FROM CURRENT }} 
      | TIME ZONE time_zone
      | CURRENT_SCHEMA schema
      | NAMES encoding_name
      | ROLE role_name PASSWORD 'password'
      | SESSION AUTHORIZATION { role_name PASSWORD 'password' | DEFAULT }
      | XML OPTION { DOCUMENT | CONTENT }
    } ; 参数说明 config_parameter 可设置的运行时参数的名称。可用的运行时参数可以使用SHOW ALL命令查看。 value config_parameter的新值。可以声明为字符串常量、标识符、数字，或者逗号分隔的列表。DEFAULT用于把这些参数设置为它们的缺省值。 DEFAULT OFF RESET 用户指定的值：需要满足修改参数的取值限制 FROM CURRENT 取当前会话中的值设置为configuration_parameter的值。 TIME ZONE timezone 用于指定当前会话的本地时区。 取值范围：有效的本地时区。该选项对应的运行时参数名称为TimeZone，DEFAULT缺省值为PRC。 CURRENT_SCHEMA schema CURRENT_SCHEMA用于指定当前的模式。 取值范围：已存在模式名称。如果模式名不存在，会导致CURRENT_SCHEMA值为空。 SCHEMA schema 同CURRENT_SCHEMA。此处的schema是个字符串。 NAMES encoding_name 用于设置客户端的字符编码。等价于set client_encoding to encoding_name。 取值范围：有效的字符编码。该选项对应的运行时参数名称为client_encoding，默认编码为UTF8。 role_name 取值范围：字符串。要符合 标识符命名规范 。 password 角色的密码。要求符合密码的命名规则。 SESSION AUTHORIZATION 当前会话的用户表示符。 XML OPTION { DOCUMENT | CONTENT } 用于设置XML的解析方式。 取值范围：CONTENT（缺省）、DOCUMENT 示例 -- 创建模式ds。 gaussdb=# CREATE SCHEMA ds;

--设置模式搜索路径。 gaussdb=# SET SEARCH_PATH TO ds, public;

--设置日期时间风格为传统的POSTGRES风格（日在月前）。 gaussdb=# SET DATESTYLE TO postgres, dmy;

--设置当前会话的字符编码为UTF8。 gaussdb=# ALTER SESSION SET NAMES 'UTF8';

--设置时区为加州伯克利。 gaussdb=# SET TIME ZONE 'PST8PDT';

--设置时区为意大利。 gaussdb=# SET TIME ZONE 'Europe/Rome';

--设置当前模式。 gaussdb=# ALTER SESSION SET CURRENT_SCHEMA TO tpcds;

--设置XML OPTION为DOCUMENT。 gaussdb=# ALTER SESSION SET XML OPTION DOCUMENT;

--创建角色joe，并设置会话的角色为joe。 gaussdb=# CREATE ROLE joe WITH PASSWORD ' ******** '; gaussdb=# ALTER SESSION SET SESSION AUTHORIZATION joe PASSWORD ' ******** ';

--切换到默认用户。 gaussdb => ALTER SESSION SET SESSION AUTHORIZATION default;

--删除ds模式。 gaussdb=# DROP SCHEMA ds;

--删除joe。 gaussdb=# DROP ROLE joe;

--开启事务,设置事务级别 gaussdb=# START TRANSACTION; gaussdb=# ALTER SESSION SET TRANSACTION READ ONLY; gaussdb=# END; 相关链接 SET

ALTER MATERIALIZED VIEW ALTER MATERIALIZED VIEW 功能描述 更改一个现有物化视图的多个辅助属性。 可用于ALTER MATERIALIZED VIEW的语句形式和动作是ALTER TABLE的一个子集，并且在用于物化视图时具有相同的含义。详见 ALTER TABLE 。 注意事项 只有物化视图的所有者有权限执行ALTER MATERIALIZED VIEW命令，系统管理员默认拥有此权限。 不支持更改物化视图结构。 语法格式 修改物化视图的所属用户。 ALTER MATERIALIZED VIEW [ IF EXISTS ] mv_name
    OWNER TO new_owner; 修改物化视图的列。 ALTER MATERIALIZED VIEW [ IF EXISTS ] mv_name
    RENAME [ COLUMN ] column_name TO new_column_name; 重命名物化视图。 ALTER MATERIALIZED VIEW [ IF EXISTS ] mv_name
    RENAME TO new_name; 参数说明 mv_name 一个现有物化视图的名称，可以用模式修饰。 取值范围：字符串，符合 标识符命名规范 。 column_name 一个新的或者现有的列的名称。 取值范围：字符串，符合 标识符命名规范 。 new_column_name 一个现有列的新名称。 new_owner 该物化视图的新拥有者的用户名。 new_name 该物化视图的新名称。 示例 --创建表。 gaussdb=# CREATE TABLE my_table (c1 int, c2 int) WITH(STORAGE_TYPE=ASTORE);

--创建全量物化视图。 gaussdb=# CREATE MATERIALIZED VIEW foo AS SELECT * FROM my_table;

--把物化视图foo重命名为bar。 gaussdb=# ALTER MATERIALIZED VIEW foo RENAME TO bar;

--删除全量物化视图。 gaussdb=# DROP MATERIALIZED VIEW bar;

--删除表my_table。 gaussdb=# DROP TABLE my_table; 相关链接 CREATE MATERIALIZED VIEW ， CREATE INCREMENTAL MATERIALIZED VIEW ， DROP MATERIALIZED VIEW ， REFRESH INCREMENTAL MATERIALIZED VIEW ， REFRESH MATERIALIZED VIEW

ALTER DATABASE LINK ALTER DATABASE LINK 功能描述 修改DATABASE LINK对象。DATABASE LINK详细说明请见 DATABASE LINK 。 注意事项 目前仅支持修改DATABASE LINK对象的用户名和密码。 语法格式 ALTER [ PUBLIC ] DATABASE LINK dblink CONNECT TO user IDENTIFIED BY 'password'; 参数说明 dblink 连接名称。 user 远端被连接数据库用户名。 password 远端被连接数据库用户密码。 PUBLIC 连接类型，不加PUBLIC默认PRIVATE。 示例 gaussdb=# CREATE USER user01 WITH SYSADMIN PASSWORD '********'; gaussdb=# SET ROLE user01 PASSWORD '********';

--创建公共dblink gaussdb=# CREATE PUBLIC DATABASE LINK public_dblink CONNECT TO 'user1' IDENTIFIED BY '********' USING (host '192.168.11.11',port '54399',dbname 'db01');

-- 修改dblink对象信息 gaussdb=# ALTER PUBLIC DATABASE LINK public_dblink CONNECT TO 'user2' IDENTIFIED BY '********'; gaussdb=# DROP PUBLIC DATABASE LINK public_dblink; gaussdb=# RESET ROLE; gaussdb=# DROP USER USER01 CASCADE; 相关链接 CREATE DATABASE LINK ， DROP DATABASE LINK

ALTER VIEW ALTER VIEW 功能描述 ALTER VIEW更改视图的各种辅助属性。（如果用户是更改视图的查询定义，要使用CREATE OR REPLACE VIEW。） 注意事项 只有视图的所有者或者被授予了视图ALTER权限的用户才可以执行ALTER VIEW命令，系统管理员默认拥有该权限。针对所要修改属性的不同，对其还有以下权限约束： 修改视图的模式，当前用户必须是视图的所有者或者系统管理员，且要有新模式的CREATE权限。 修改视图的所有者，当前用户必须是视图的所有者或者系统管理员，且该用户必须是新所有者角色的成员，并且此角色必须有视图所在模式的CREATE权限。 禁止修改视图中列的类型。 语法格式 设置视图列的默认值。 ALTER VIEW [ IF EXISTS ] view_name
    ALTER [ COLUMN ] column_name SET DEFAULT expression; 取消列视图列的默认值。 ALTER VIEW [ IF EXISTS ] view_name
    ALTER [ COLUMN ] column_name DROP DEFAULT; 修改视图的所有者。 ALTER VIEW [ IF EXISTS ] view_name 
    OWNER TO new_owner; 重命名视图。 ALTER VIEW [ IF EXISTS ] view_name 
    RENAME TO new_name; 设置视图的所属模式。 ALTER VIEW [ IF EXISTS ] view_name 
    SET SCHEMA new_schema; 设置视图的选项。 ALTER VIEW [ IF EXISTS ] view_name
    SET ( { view_option_name [ = view_option_value ] } [, ... ] ); 重置视图的选项。 ALTER VIEW [ IF EXISTS ] view_name
    RESET ( view_option_name [, ... ] ); 参数说明 IF EXISTS 使用这个选项，如果视图不存在时不会产生错误，仅有会有一个提示信息。 view_name 视图名称，可以用模式修饰。 取值范围：字符串，已经存在的视图名。 column_name 可选的名称列表，视图的字段名。如果没有给出，字段名取自查询中的字段名。 取值范围：字符串，已经存在的视图名。 SET/DROP DEFAULT 设置或删除一个列的缺省值，该参数暂无实际意义。 new_owner 视图新所有者的用户名称。 new_name 视图的新名称。 new_schema 视图的新模式。 view_option_name [ = view_option_value ] 该子句为视图指定一个可选的参数。 security_barrier：设置视图是否提供行级安全。取值范围为Boolean类型。缺省值为true。 expression 常量、函数或SQL表达式。 示例 重命名视图。 --创建test_tbl表。 gaussdb=# CREATE TABLE test_tb1(col1 INT,col2 INT);
--创建视图。 gaussdb=# CREATE VIEW abc AS SELECT * FROM test_tb1;
--重命名视图。 gaussdb=# ALTER VIEW IF EXISTS abc RENAME TO test_v1;
--查看视图。 gaussdb=# \dv
